from langchain_core.tools import StructuredTool
from pydantic import BaseModel, Field

# Well-described module using StructuredTool with Pydantic schema
class CalculatorInput(BaseModel):
    expression: str = Field(
        description=(
            "A Python arithmetic expression using only numbers and operators "
            "+, -, *, /, **, and parentheses. Example: '234.50 * 0.15'."
            " Do NOT include variable names, strings, or function calls."
        )
    )

calculator_tool = StructuredTool.from_function(
    func=lambda expression: str(eval(expression, {"__builtins__": {}})),
    name="Calculator",
    description="Evaluates arithmetic. Use for any calculation involving numbers.",
    args_schema=CalculatorInput,
)

# Module with robust error handling
class DatabaseInput(BaseModel):
    sql: str = Field(description="A SQL SELECT statement against the 'products' table.")

def safe_query(sql: str) -> str:
    import re
    if not re.match(r"^SELECT", sql.strip(), re.IGNORECASE):
        return "[Error: only SELECT statements are allowed]"
    # Execute against actual DB
    try:
        # conn.execute(sql) ...
        return "[query result]"
    except Exception as e:
        return f"[DB Error: {e}]"

db_tool = StructuredTool.from_function(
    func=safe_query,
    name="Database",
    description="Queries the products database. Use for price, stock, or product info.",
    args_schema=DatabaseInput,
)

import difflib
from dataclasses import dataclass
from typing import Optional

@dataclass
class RoutingResult:
    module_name: str
    args: str
    confidence: str  # "exact" | "fuzzy" | "fallback"

def route_with_fallback(
    raw_output: str,
    modules: list[MRKLModule],
    llm,
) -> RoutingResult:
    """Parse router output with a three-tier fallback."""
    valid_names = {m.name for m in modules}

    # Tier 1: exact parse
    match = re.search(r'\[([A-Za-z_]+)\((.*)\)\]', raw_output, re.DOTALL)
    if match:
        name, args = match.group(1), match.group(2)
        if name in valid_names:
            return RoutingResult(name, args, "exact")

    # Tier 2: fuzzy match on module name
    if match:
        name = match.group(1)
        close = difflib.get_close_matches(name, valid_names, n=1, cutoff=0.7)
        if close:
            return RoutingResult(close[0], match.group(2), "fuzzy")

    # Tier 3: re-prompt with explicit constraint
    repair_prompt = (
        f"The previous response was unparseable. "
        f"You MUST respond ONLY as: [MODULE_NAME(args)] "
        f"where MODULE_NAME is one of: {sorted(valid_names)}.\n"
        f"Original query: {raw_output}"
    )
    repaired = llm.invoke(repair_prompt).content
    match2 = re.search(r'\[([A-Za-z_]+)\((.*)\)\]', repaired, re.DOTALL)
    if match2 and match2.group(1) in valid_names:
        return RoutingResult(match2.group(1), match2.group(2), "fallback")

    # Final fallback: route to general LLM module
    return RoutingResult("llm", raw_output, "fallback")

from typing import Callable, Optional
import threading

class ModuleRegistry:
    """Thread-safe registry for MRKL modules."""

    def __init__(self):
        self._modules: dict[str, MRKLModule] = {}
        self._lock = threading.RLock()
        self._call_counts: dict[str, int] = {}

    def register(self, module: MRKLModule) -> None:
        with self._lock:
            self._modules[module.name] = module
            self._call_counts[module.name] = 0

    def unregister(self, name: str) -> None:
        with self._lock:
            self._modules.pop(name, None)
            self._call_counts.pop(name, None)

    def get(self, name: str) -> Optional[MRKLModule]:
        with self._lock:
            return self._modules.get(name)

    def all_modules(self) -> list[MRKLModule]:
        with self._lock:
            return list(self._modules.values())

    def record_call(self, name: str) -> None:
        with self._lock:
            if name in self._call_counts:
                self._call_counts[name] += 1

    def stats(self) -> dict[str, int]:
        with self._lock:
            return dict(self._call_counts)

    def build_prompt_descriptions(self) -> str:
        return "\n".join(
            f"- {m.name}: {m.description}"
            for m in self.all_modules()
        )

# Global registry — modules self-register at import time
registry = ModuleRegistry()

def mrkl_module(name: str, description: str, module_type: str = "neural"):
    """Decorator that auto-registers a function as a MRKL module."""
    def decorator(fn: Callable[[str], str]) -> Callable[[str], str]:
        registry.register(MRKLModule(
            name=name,
            description=description,
            fn=fn,
            module_type=module_type,
        ))
        return fn
    return decorator

# Usage: any module can self-register
@mrkl_module("sentiment", "Classify text sentiment as positive/neutral/negative", "neural")
